/* --------------------------------------------------------------------------
   Section renderer — routes each section to its special components
   -------------------------------------------------------------------------- */
function takeawaysFromSubs(subs) {
  const tk = subs.find((s) => /key takeaways/i.test(s.title));
  if (!tk) return { items: null, rest: subs };
  const listBlock = tk.blocks.find((b) => b.type === "list");
  const items = listBlock ? listBlock.items : null;
  return { items, rest: subs.filter((s) => s !== tk) };
}

function buildVolumeData(section) {
  // find "Volume Landmarks by Training Age" table in section 2
  for (const sub of section.subs) {
    for (const b of sub.blocks) {
      if (b.type === "table") {
        const hdr = b.header.join(" ").toLowerCase();
        if (hdr.includes("beginner") && hdr.includes("intermediate") && hdr.includes("advanced")) {
          return b.rows.map((r) => {
            const lv = (cell) => {
              const parts = cell.split("/").map((x) => parseRange(x));
              return parts.length === 3 ? parts : [0, 0, 0];
            };
            return {
              muscle: r[0].replace(/\(.*?\)/g, "").trim(),
              levels: { Beginner: lv(r[1]), Intermediate: lv(r[2]), Advanced: lv(r[3]) },
            };
          });
        }
      }
    }
  }
  return null;
}

function SectionView({ section, registerRef, onManualComplete, completed }) {
  const { num } = section;
  const { items: takeaways, rest } = takeawaysFromSubs(section.subs);

  let inner;

  if (num === 1) {
    // Intro: render subs, but replace the misconceptions sub with MythBuster grid
    inner = rest.map((sub, i) => {
      if (/misconception/i.test(sub.title)) {
        return (
          <div key={i} className="mw-subsection">
            <h2 className="mw-h2">{sub.title}</h2>
            <div className="mw-myth-grid">
              {section.myths.map((m, mi) => (
                <MythBuster key={mi} myth={m.myth} reality={m.reality} />
              ))}
            </div>
          </div>
        );
      }
      return <Subsection key={i} sub={sub} />;
    });
  } else if (num === 2) {
    const volData = buildVolumeData(section);
    inner = rest.map((sub, i) => {
      if (/volume landmark/i.test(sub.title) && volData) {
        return (
          <div key={i} className="mw-subsection">
            <h2 className="mw-h2">{sub.title}</h2>
            <VolumeChart data={volData} />
            <Blocks blocks={sub.blocks} />
          </div>
        );
      }
      return <Subsection key={i} sub={sub} />;
    });
  } else if (num === 4) {
    inner = <MuscleSelector subs={rest} />;
  } else if (num === 10) {
    const splitSubs = rest.filter((s) => !/master split comparison/i.test(s.title));
    const master = rest.find((s) => /master split comparison/i.test(s.title));
    inner = (
      <>
        <SplitComparison subs={splitSubs} />
        {master && <div className="mw-subsection"><h2 className="mw-h2">{master.title}</h2><Blocks blocks={master.blocks} /></div>}
      </>
    );
  } else if (num === 11) {
    inner = (
      <>
        <ProgressionTracker />
        {rest.map((sub, i) => <Subsection key={i} sub={sub} />)}
      </>
    );
  } else if (num === 15) {
    inner = rest.map((sub, i) => {
      if (/flowchart/i.test(sub.title)) {
        return (
          <div key={i} className="mw-subsection">
            <h2 className="mw-h2">{sub.title}</h2>
            <PlateauDiagnostic />
          </div>
        );
      }
      return <Subsection key={i} sub={sub} />;
    });
  } else if (num === 19) {
    inner = (
      <div className="mw-prog-cards">
        {rest.map((sub, i) => <ProgramCard key={i} sub={sub} />)}
      </div>
    );
  } else if (num === 20) {
    inner = <FAQ faqs={section.faqs} />;
  } else if (num === 21) {
    inner = <CheatSheet subs={rest} />;
  } else if (num === 22) {
    // My favorite workout splits — each "Split N" becomes an expandable card
    const splitSubs = rest.filter((s) => /^split\s*\d+/i.test(s.title));
    const otherSubs = rest.filter((s) => !/^split\s*\d+/i.test(s.title));
    inner = (
      <>
        <div className="mw-prog-cards">
          {splitSubs.map((sub, i) => <ProgramCard key={i} sub={sub} prefix="S" />)}
        </div>
        {otherSubs.map((sub, i) => <Subsection key={i} sub={sub} />)}
      </>
    );
  } else if (num === 23) {
    inner = rest.map((sub, i) => {
      if (/blueprint/i.test(sub.title)) {
        // blueprint cards + golden equation
        return (
          <div key={i} className="mw-subsection">
            <h2 className="mw-h2">{sub.title}</h2>
            <CheatSheetInline blocks={sub.blocks} />
            <GoldenEquation />
          </div>
        );
      }
      return <Subsection key={i} sub={sub} />;
    });
  } else {
    inner = rest.map((sub, i) => <Subsection key={i} sub={sub} />);
  }

  return (
    <section
      id={section.id}
      ref={(el) => registerRef(section.id, el)}
      className="mw-section"
    >
      <SectionHeader num={section.num} title={section.title} category={section.category} />
      {section.intro && section.intro.length > 0 && (
        <div className="mw-intro"><Blocks blocks={section.intro} /></div>
      )}
      {inner}
      {takeaways && <KeyTakeawaysBox items={takeaways} />}
      <div className="mw-section__foot">
        <button
          className={"mw-markread" + (completed ? " is-done" : "")}
          onClick={() => onManualComplete(section.id)}
        >
          {completed ? <><Icon name="check" /> SECTION READ</> : "MARK AS READ"}
        </button>
      </div>
    </section>
  );
}

function Subsection({ sub }) {
  if (/key takeaways/i.test(sub.title)) return null;
  return (
    <div className="mw-subsection">
      <h2 className="mw-h2">{sub.title}</h2>
      <Blocks blocks={sub.blocks} />
    </div>
  );
}

// Golden-equation blueprint helper: render blueprint tables/lists as a tight grid
function CheatSheetInline({ blocks }) {
  // split by h3 into cards
  const cards = [];
  let cur = null;
  blocks.forEach((b) => {
    if (b.type === "h3") {
      if (cur) cards.push(cur);
      cur = { title: b.text, blocks: [] };
    } else if (cur) cur.blocks.push(b);
    else { cards.push({ title: null, blocks: [b] }); }
  });
  if (cur) cards.push(cur);
  // filter out the golden-equation card (rendered separately)
  const visible = cards.filter((c) => !/golden equation/i.test(c.title || ""));
  return (
    <div className="mw-cheats">
      {visible.map((c, i) => (
        <div className="mw-cheat" key={i}>
          {c.title && <div className="mw-cheat__head"><Icon name="bookmark" /><span>{c.title}</span></div>}
          <div className="mw-cheat__body"><Blocks blocks={c.blocks} /></div>
        </div>
      ))}
    </div>
  );
}

/* --------------------------------------------------------------------------
   Icons — minimal inline SVG set
   -------------------------------------------------------------------------- */
function Icon({ name }) {
  const common = { width: 14, height: 14, viewBox: "0 0 24 24", fill: "none", stroke: "currentColor", strokeWidth: 2, strokeLinecap: "round", strokeLinejoin: "round" };
  switch (name) {
    case "check": return <svg {...common}><polyline points="20 6 9 17 4 12" /></svg>;
    case "bookmark": return <svg {...common}><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" /></svg>;
    case "target": return <svg {...common}><circle cx="12" cy="12" r="9" /><circle cx="12" cy="12" r="4" /><circle cx="12" cy="12" r="0.5" fill="currentColor" /></svg>;
    case "atom": return <svg {...common}><circle cx="12" cy="12" r="1.5" fill="currentColor" /><ellipse cx="12" cy="12" rx="9" ry="4" /><ellipse cx="12" cy="12" rx="9" ry="4" transform="rotate(60 12 12)" /><ellipse cx="12" cy="12" rx="9" ry="4" transform="rotate(120 12 12)" /></svg>;
    case "flag": return <svg {...common}><path d="M4 15s1-1 4-1 5 2 8 2 4-1 4-1V3s-1 1-4 1-5-2-8-2-4 1-4 1z" /><line x1="4" y1="22" x2="4" y2="15" /></svg>;
    case "search": return <svg {...common}><circle cx="11" cy="11" r="7" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>;
    case "x": return <svg {...common}><line x1="18" y1="6" x2="6" y2="18" /><line x1="6" y1="6" x2="18" y2="18" /></svg>;
    case "plus": return <svg {...common}><line x1="12" y1="5" x2="12" y2="19" /><line x1="5" y1="12" x2="19" y2="12" /></svg>;
    case "minus": return <svg {...common}><line x1="5" y1="12" x2="19" y2="12" /></svg>;
    case "chevron": return <svg {...common}><polyline points="9 18 15 12 9 6" /></svg>;
    case "caret-down": return <svg {...common}><polyline points="6 9 12 15 18 9" /></svg>;
    case "caret-right": return <svg {...common}><polyline points="9 6 15 12 9 18" /></svg>;
    case "arrow": return <svg {...common}><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></svg>;
    case "reset": return <svg {...common}><polyline points="1 4 1 10 7 10" /><path d="M3.51 15a9 9 0 1 0 2.13-9.36L1 10" /></svg>;
    default: return null;
  }
}

/* ==========================================================================
   APP SHELL
   ========================================================================== */
export default function MogwardTrainingProtocol() {
  const sections = CONTENT.sections;
  const sectionRefs = useRef({});
  const contentRef = useRef(null);
  const [activeId, setActiveId] = useState(sections[0].id);
  const [manualSet, setManualSet] = useState(() => new Set());
  const [mobileNav, setMobileNav] = useState(false);

  const registerRef = useCallback((id, el) => {
    if (el) sectionRefs.current[id] = el;
  }, []);

  // Completion is driven solely by the manual "MARK AS READ" toggle.
  const completedSet = manualSet;

  // IntersectionObserver: active-section highlight only (no auto-complete).
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        // pick the most-visible section for active highlight
        const visible = entries
          .filter((e) => e.isIntersecting)
          .sort((a, b) => b.intersectionRatio - a.intersectionRatio);
        if (visible.length) setActiveId(visible[0].target.id);
      },
      { root: contentRef.current, threshold: [0.15, 0.4, 0.7], rootMargin: "-80px 0px -40% 0px" }
    );
    Object.values(sectionRefs.current).forEach((el) => el && observer.observe(el));
    return () => observer.disconnect();
  }, [sections]);

  const progress = Math.round((completedSet.size / sections.length) * 100);
  const allComplete = completedSet.size === sections.length;

  const scrollTo = (id) => {
    const el = sectionRefs.current[id];
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
    setMobileNav(false);
  };

  const markComplete = (id) => {
    setManualSet((prev) => {
      const n = new Set(prev);
      if (n.has(id)) n.delete(id);
      else n.add(id);
      return n;
    });
  };

  const activeNum = sections.find((s) => s.id === activeId)?.num || 1;
  const completedDate = useMemo(
    () => new Date().toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" }),
    []
  );

  return (
    <div className="mw-app">
      <StyleSheet />

      {/* HEADER */}
      <header className="mw-header">
        <div className="mw-header__left">
          <button className="mw-burger" onClick={() => setMobileNav((v) => !v)} aria-label="Menu">
            <span /><span /><span />
          </button>
          <div className="mw-logo">
            <span className="mw-logo__badge">M</span>
            <span className="mw-logo__word">MOGWARD</span>
          </div>
        </div>
        <div className="mw-header__right">
          <span className="mw-header__title">TRAINING PROTOCOL</span>
          <span className="mw-header__sec">S{String(activeNum).padStart(2, "0")}</span>
        </div>
      </header>

      <div className="mw-layout">
        {/* SIDEBAR */}
        <aside className={"mw-sidebar" + (mobileNav ? " is-open" : "")}>
          <div className="mw-sidebar__progress">
            <div className="mw-sidebar__progress-top">
              <span>PROTOCOL PROGRESS</span>
              <span className="mw-sidebar__pct">{progress}%</span>
            </div>
            <div className="mw-progressbar">
              <div className="mw-progressbar__fill" style={{ width: `${progress}%` }} />
            </div>
            <div className="mw-sidebar__count">
              {completedSet.size} / {sections.length} SECTIONS
            </div>
          </div>

          <nav className="mw-nav">
            {sections.map((s) => {
              const isActive = s.id === activeId;
              const isDone = completedSet.has(s.id);
              return (
                <button
                  key={s.id}
                  className={"mw-nav__item" + (isActive ? " is-active" : "") + (isDone ? " is-done" : "")}
                  onClick={() => scrollTo(s.id)}
                >
                  <span className="mw-nav__num">S{String(s.num).padStart(2, "0")}</span>
                  <span className="mw-nav__label">{s.short}</span>
                  {isDone && <span className="mw-nav__check"><Icon name="check" /></span>}
                </button>
              );
            })}
          </nav>

          <div className="mw-sidebar__foot">
            <button
              className={"mw-complete-btn" + (allComplete ? " is-unlocked" : "")}
              onClick={() => scrollTo(sections[sections.length - 1].id)}
              disabled={false}
            >
              {allComplete ? "VIEW CERTIFICATE" : "MARK COMPLETE"}
            </button>
            {!allComplete && (
              <p className="mw-sidebar__hint">
                Read all {sections.length} sections to unlock your certificate.
              </p>
            )}
          </div>
        </aside>

        {mobileNav && <div className="mw-scrim" onClick={() => setMobileNav(false)} />}

        {/* CONTENT */}
        <main className="mw-content" ref={contentRef}>
          <div className="mw-content__inner">
            {sections.map((s) => (
              <SectionView
                key={s.id}
                section={s}
                registerRef={registerRef}
                onManualComplete={markComplete}
                completed={completedSet.has(s.id)}
              />
            ))}
            <CompletionBadge show={allComplete} date={completedDate} />
            <footer className="mw-footer">
              <span className="mw-logo__badge">M</span>
              <span>MOGWARD · TRAINING PROTOCOL · v1</span>
            </footer>
          </div>
        </main>
      </div>
    </div>
  );
}

